// Parsear la fecha futura y calcular recordatorio (30 días antes)
const fechaFuturaStr = $input.first().json.fecha_futura;

// Intentar parsear varios formatos comunes
let fechaFutura;
const formats = ['dd/MM/yyyy', 'd/M/yyyy', 'yyyy-MM-dd', 'dd-MM-yyyy', 'd-M-yyyy'];

for (const fmt of formats) {
  const parsed = DateTime.fromFormat(fechaFuturaStr, fmt);
  if (parsed.isValid) {
    fechaFutura = parsed;
    break;
  }
}

// Si no se pudo parsear, intentar desde ISO
if (!fechaFutura) {
  fechaFutura = DateTime.fromISO(fechaFuturaStr);
}

// Si todavía no es válida, usar 3 meses desde hoy
if (!fechaFutura.isValid) {
  fechaFutura = DateTime.now().plus({ months: 3 });
}

// Calcular fecha de recordatorio (30 días antes)
const fechaRecordatorio = fechaFutura.minus({ days: 30 });

// Asegurar que no sea en el pasado
const fechaFinal = fechaRecordatorio < DateTime.now() ? DateTime.now().plus({ days: 1 }) : fechaRecordatorio;

return [{
  json: {
    ...$input.first().json,
    fecha_futura_parseada: fechaFutura.toFormat('yyyy-MM-dd'),
    fecha_recordatorio: fechaFinal.toFormat('yyyy-MM-dd'),
    fecha_recordatorio_iso: fechaFinal.toISO()
  }
}];

